-- 1) Columna para enlazar fotos por clave (idempotente)
ALTER TABLE public.properties ADD COLUMN IF NOT EXISTS clave_control text;

-- 2) Permitir tipos adicionales (Local, Bodega) ademas de los originales
ALTER TABLE public.properties DROP CONSTRAINT IF EXISTS properties_tipo_check;
ALTER TABLE public.properties
  ADD CONSTRAINT properties_tipo_check
  CHECK (tipo IN ('Casa','Departamento','Terreno','Local','Bodega'));

-- 3) Dejar SOLO estas propiedades (borra el catalogo actual de ejemplo)
DELETE FROM public.properties;

